(function(window2, document2) {
  const draggable_params = {
    x: 20,
    // right
    y: 100,
    // bottom 该值必须是初始定位样式值的倍数(比如使用750px设计稿的需要设置初始值为设计稿的一半)，否则首次拖拽可能会错位
    startX: 0,
    startY: 0,
    endX: 0,
    endY: 0
  };
  const rtDraggable = {
    init(node) {
      node && node.addEventListener("touchstart", (e) => {
        draggable_params.startX = e.touches[0].pageX;
        draggable_params.startY = e.touches[0].pageY;
      });
      node && node.addEventListener("touchend", (e) => {
        draggable_params.x = draggable_params.endX;
        draggable_params.y = draggable_params.endY;
        draggable_params.startX = 0;
        draggable_params.startY = 0;
      });
      node && node.addEventListener("touchmove", (e) => {
        if (e.touches.length > 0) {
          let offsetX = e.touches[0].pageX - draggable_params.startX, offsetY = e.touches[0].pageY - draggable_params.startY;
          let x = draggable_params.x - offsetX, y = draggable_params.y - offsetY;
          if (x + node.offsetWidth > document2.documentElement.offsetWidth) {
            x = document2.documentElement.offsetWidth - node.offsetWidth;
          }
          if (y + node.offsetHeight > document2.documentElement.offsetHeight) {
            y = document2.documentElement.offsetHeight - node.offsetHeight;
          }
          if (x < 0) {
            x = 0;
          }
          if (y < 0) {
            y = 0;
          }
          if (node.style.position !== "fixed") {
            node.style.position = "fixed";
          }
          node.style.right = x + "px";
          node.style.bottom = y + "px";
          draggable_params.endX = x;
          draggable_params.endY = y;
          e.preventDefault();
        }
      });
    }
  };
  window2.rtDraggable = rtDraggable;
})(window, document);
